export const masterEndpoint = {
  getWarehouses: async () => {
    const res = await apiClient.get<BffResponse<WarehouseDto[]>>('/master/warehouses');
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },

  getPartners: async (type?: string) => {
    const qs = type ? `?type=${type}` : '';
    const res = await apiClient.get<BffResponse<PartnerDto[]>>(`/master/partners${qs}`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },

  getDepartments: async () => {
    const res = await apiClient.get<BffResponse<DepartmentDto[]>>('/hr/departments');
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },

  getMaterials: async () => {
    const result = await fetchPaginated<MaterialDto>('/master/materials', {
      page: 1,
      pageSize: 500,
      isActive: true,
    });
    return result.items;
  },

  searchMaterials: async (params: { search?: string; page: number; pageSize: number }) => {
    const result = await fetchPaginated<MaterialDto>('/master/materials', {
      search: params.search,
      page: params.page,
      pageSize: params.pageSize,
      isActive: true,
    });
    const totalPages = Math.max(1, Math.ceil(result.totalCount / params.pageSize));
    return {
      items: result.items,
      page: result.page,
      totalPages,
    };
  },
};
